@@ -319,6 +344,98 @@
 			PF(start, (double)p);
 		break;
 	}
+	case '(': {
+		char	*end = index(fmt + 1, ')');
+
+		if (end == NULL) {
+			warnx("No closing ')' detected");
+			return (NULL);
+		}
+			
+		if (subfmt != NULL) {
+			warnx("Subformat \"%s\" already set", subfmt);
+			return NULL;
+		}
+		if (end == fmt)
+			break; /* Empty format -- presume default */
+		asprintf(&subfmt, "%c%.*s", nextch,
+		    (int)(end - fmt - 1), fmt + 1);
+		if (subfmt == NULL) {
+			warnx("%s", strerror(ENOMEM));
+			return (NULL);
+		}
+		*fmt = nextch;
+		*end = '%';
+		return (end);
+	}
+	case 'T': {
+		char		*timebuf = NULL;
+		size_t		 buflen, timelen;
+		const char	*timefmt;
+		intmax_t	 val;
+		uintmax_t	 uval;
+		struct timeval	 tv;
+
+		if (subfmt == NULL)
+			timefmt = "%a %b %d %T %Z %Y"; /* date(1)'s default */
+		else
+			timefmt = subfmt;
+		if (getnum(&val, &uval, 1) || (tv.tv_sec = val) != val) {
+			if (subfmt != NULL) {
+				free(subfmt);
+				subfmt = NULL;
+			}
+			*rval = 1;
+			return NULL;
+		}
+		switch (tv.tv_sec) {
+		case -2:
+#if defined(SHELL)
+			getstarttime(&tv);
+			break;
+		/* Outside of shell, -2 and -1 both mean current time */
+#endif
+		case -1:
+			gettimeofday(&tv, NULL);
+			break;
+		default:
+			if (tv.tv_sec < 0) {
+				warnx("Can not turn %jd into date/time", val);
+				if (subfmt != NULL) {
+					free(subfmt);
+					subfmt = NULL;
+				}
+				*rval = 1;
+				return NULL;
+			}
+		}
+		/*
+		 * No (easy) way to know, how big the buffer needs to be.
+		 * Start small and double as necessary:
+		 */
+		buflen = strlen(timefmt) * 4; /* harmless overestimate */
+		do {
+			buflen *= 2;
+			timebuf = realloc(timebuf, buflen);
+			if (timebuf == NULL) {
+				if (subfmt != NULL) {
+					free(subfmt);
+					subfmt = NULL;
+				}
+				warnx("%s", strerror(ENOMEM));
+				return (NULL);
+			}
+			timelen = strftime(timebuf, buflen, timefmt,
+			    localtime(&tv.tv_sec));
+		} while(timelen == 0);
+		fputs(timebuf, stdout);
+		free(timebuf);
+		if (subfmt != NULL) {
+			free(subfmt);
+			subfmt = NULL;
+		}
+		break;
+	}
 	default:
 		warnx("illegal format character %c", convch);
 		return (NULL);
